contracts/EventLogger.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

/**
 * @title  EventLogger
 * @notice Records every CI/CD pipeline event immutably on-chain.
 *         Called by blockchain-logger.js at each stage of the
 *         GitHub Actions workflow: build started, tests passed,
 *         integrity verified, deployment triggered, etc.
 *
 * @dev    Works alongside PipelineRegistry.sol. Each log entry
 *         references a pipelineId registered there.
 *         The React dashboard reads this contract's emitted events
 *         to render the full audit trail.
 */
contract EventLogger {

    // ─────────────────────────────────────────────
    //  Enums
    // ─────────────────────────────────────────────

    /**
     * @notice The stage of the CI/CD pipeline that triggered this log entry.
     *         Stored as uint8 on-chain for gas efficiency.
     *
     *   PIPELINE_TRIGGERED  — a git push or manual trigger started the pipeline
     *   BUILD_STARTED       — the build job began
     *   BUILD_SUCCESS       — build completed without errors
     *   BUILD_FAILED        — build failed
     *   TESTS_STARTED       — test suite started running
     *   TESTS_PASSED        — all tests passed
     *   TESTS_FAILED        — one or more tests failed
     *   INTEGRITY_VERIFIED  — hash matched the approved hash in PipelineRegistry
     *   INTEGRITY_FAILED    — hash mismatch detected — possible tampering
     *   DEPLOY_STARTED      — deployment job began
     *   DEPLOY_SUCCESS      — deployment completed successfully
     *   DEPLOY_FAILED       — deployment failed
     */
    enum Stage {
        PIPELINE_TRIGGERED,
        BUILD_STARTED,
        BUILD_SUCCESS,
        BUILD_FAILED,
        TESTS_STARTED,
        TESTS_PASSED,
        TESTS_FAILED,
        INTEGRITY_VERIFIED,
        INTEGRITY_FAILED,
        DEPLOY_STARTED,
        DEPLOY_SUCCESS,
        DEPLOY_FAILED
    }

    // ─────────────────────────────────────────────
    //  Structs
    // ─────────────────────────────────────────────

    /**
     * @notice A single on-chain log entry for one CI/CD event.
     * @param logId         Auto-incremented unique ID for this log entry.
     * @param pipelineId    References the pipeline in PipelineRegistry.
     * @param runId         The GitHub Actions run ID (from ${{ github.run_id }}).
     * @param stage         Which pipeline stage this entry represents.
     * @param configHash    SHA-256 hash of the workflow YAML at the time
     *                      this event was logged. Allows post-hoc comparison.
     * @param commitHash    The git commit SHA that triggered this run.
     * @param actor         GitHub username that triggered the pipeline
     *                      (stored as a string, not an address).
     * @param notes         Optional free-text field — e.g. error message on failure,
     *                      environment name on deploy, test count on pass.
     * @param loggedBy      The Ethereum address of the wallet that sent this tx
     *                      (your GitHub Actions bot wallet).
     * @param timestamp     Block timestamp when this entry was recorded.
     */
    struct LogEntry {
        uint256 logId;
        uint256 pipelineId;
        uint256 runId;
        Stage   stage;
        bytes32 configHash;
        string  commitHash;
        string  actor;
        string  notes;
        address loggedBy;
        uint256 timestamp;
    }

    // ─────────────────────────────────────────────
    //  State variables
    // ─────────────────────────────────────────────

    /// @notice Address that deployed this contract.
    address public owner;

    /// @notice Addresses permitted to write log entries.
    ///         The GitHub Actions bot wallet must be authorised here.
    mapping(address => bool) public authorisedLoggers;

    /// @notice All log entries, indexed by logId (1-based).
    mapping(uint256 => LogEntry) public logEntries;

    /// @notice All logIds belonging to a given pipelineId.
    ///         Used by the dashboard to fetch logs per pipeline.
    mapping(uint256 => uint256[]) public logsByPipeline;

    /// @notice All logIds belonging to a given GitHub Actions runId.
    ///         Used to reconstruct the full timeline of a single run.
    mapping(uint256 => uint256[]) public logsByRun;

    /// @notice Total number of log entries recorded.
    uint256 public logCount;

    // ─────────────────────────────────────────────
    //  Events
    // ─────────────────────────────────────────────

    /**
     * @notice Emitted on every CI/CD event logged.
     *         The React dashboard listens for this event to update
     *         the audit trail in real time.
     *
     * @param logId       Unique ID of this entry.
     * @param pipelineId  Which pipeline this belongs to.
     * @param runId       GitHub Actions run ID.
     * @param stage       Which stage was reached.
     * @param configHash  Workflow YAML hash at time of logging.
     * @param commitHash  Git commit SHA.
     * @param actor       GitHub username that triggered the run.
     * @param loggedBy    Bot wallet address that sent the transaction.
     * @param timestamp   Block timestamp.
     */
    event CiCdEventLogged(
        uint256 indexed logId,
        uint256 indexed pipelineId,
        uint256 indexed runId,
        Stage           stage,
        bytes32         configHash,
        string          commitHash,
        string          actor,
        address         loggedBy,
        uint256         timestamp
    );

    /// @notice Emitted when a logger address is authorised.
    event LoggerAuthorised(address indexed logger, uint256 timestamp);

    /// @notice Emitted when a logger address is revoked.
    event LoggerRevoked(address indexed logger, uint256 timestamp);

    // ─────────────────────────────────────────────
    //  Modifiers
    // ─────────────────────────────────────────────

    modifier onlyOwner() {
        require(msg.sender == owner, "EventLogger: caller is not the owner");
        _;
    }

    modifier onlyAuthorised() {
        require(
            authorisedLoggers[msg.sender] || msg.sender == owner,
            "EventLogger: caller is not an authorised logger"
        );
        _;
    }

    // ─────────────────────────────────────────────
    //  Constructor
    // ─────────────────────────────────────────────

    /**
     * @notice Deploys the contract, sets the owner, and authorises
     *         the deployer as the first logger.
     */
    constructor() {
        owner = msg.sender;
        authorisedLoggers[msg.sender] = true;
        emit LoggerAuthorised(msg.sender, block.timestamp);
    }

    // ─────────────────────────────────────────────
    //  Access control (owner only)
    // ─────────────────────────────────────────────

    /**
     * @notice Authorise a wallet address to write log entries.
     *         Call this with your GitHub Actions bot wallet address
     *         after deployment.
     * @param logger  The address to authorise.
     */
    function authoriseLogger(address logger) external onlyOwner {
        require(logger != address(0), "EventLogger: zero address");
        authorisedLoggers[logger] = true;
        emit LoggerAuthorised(logger, block.timestamp);
    }

    /**
     * @notice Revoke logging permission from an address.
     * @param logger  The address to revoke.
     */
    function revokeLogger(address logger) external onlyOwner {
        authorisedLoggers[logger] = false;
        emit LoggerRevoked(logger, block.timestamp);
    }

    // ─────────────────────────────────────────────
    //  Write function
    // ─────────────────────────────────────────────

    /**
     * @notice Record a CI/CD pipeline event on-chain.
     *         Called by blockchain-logger.js from GitHub Actions.
     *
     * @param pipelineId  ID from PipelineRegistry for this pipeline.
     * @param runId       GitHub Actions ${{ github.run_id }}.
     * @param stage       The Stage enum value for this event.
     * @param configHash  SHA-256 hash of the workflow YAML (bytes32).
     * @param commitHash  Git commit SHA, e.g. "a1b2c3d4...".
     * @param actor       GitHub username, e.g. "octocat".
     * @param notes       Optional context string.
     * @return logId      The ID assigned to this new log entry.
     */
    function logEvent(
        uint256 pipelineId,
        uint256 runId,
        Stage   stage,
        bytes32 configHash,
        string  calldata commitHash,
        string  calldata actor,
        string  calldata notes
    ) external onlyAuthorised returns (uint256 logId) {
        require(pipelineId > 0,              "EventLogger: invalid pipelineId");
        require(runId > 0,                   "EventLogger: invalid runId");
        require(bytes(commitHash).length > 0,"EventLogger: commitHash required");
        require(bytes(actor).length > 0,     "EventLogger: actor required");

        logId = ++logCount;

        logEntries[logId] = LogEntry({
            logId:       logId,
            pipelineId:  pipelineId,
            runId:       runId,
            stage:       stage,
            configHash:  configHash,
            commitHash:  commitHash,
            actor:       actor,
            notes:       notes,
            loggedBy:    msg.sender,
            timestamp:   block.timestamp
        });

        logsByPipeline[pipelineId].push(logId);
        logsByRun[runId].push(logId);

        emit CiCdEventLogged(
            logId,
            pipelineId,
            runId,
            stage,
            configHash,
            commitHash,
            actor,
            msg.sender,
            block.timestamp
        );
    }

    // ─────────────────────────────────────────────
    //  Read functions
    // ─────────────────────────────────────────────

    /**
     * @notice Fetch a single log entry by its ID.
     * @param logId  The log entry to retrieve.
     */
    function getLogEntry(uint256 logId)
        external
        view
        returns (LogEntry memory)
    {
        require(logId > 0 && logId <= logCount, "EventLogger: log not found");
        return logEntries[logId];
    }

    /**
     * @notice Get all log entry IDs for a given pipeline.
     *         Use these IDs with getLogEntry() to reconstruct the full history.
     * @param pipelineId  The pipeline to query.
     */
    function getLogIdsByPipeline(uint256 pipelineId)
        external
        view
        returns (uint256[] memory)
    {
        return logsByPipeline[pipelineId];
    }

    /**
     * @notice Get all log entry IDs for a specific GitHub Actions run.
     *         Lets the dashboard show the complete timeline of one run.
     * @param runId  The GitHub Actions run ID.
     */
    function getLogIdsByRun(uint256 runId)
        external
        view
        returns (uint256[] memory)
    {
        return logsByRun[runId];
    }

    /**
     * @notice Convenience: get the most recent N log entries across
     *         all pipelines. Useful for the dashboard's "latest events" feed.
     * @param count  How many recent entries to return (max 50).
     */
    function getRecentLogs(uint256 count)
        external
        view
        returns (LogEntry[] memory entries)
    {
        if (count > 50) count = 50;
        if (count > logCount) count = logCount;

        entries = new LogEntry[](count);
        for (uint256 i = 0; i < count; i++) {
            entries[i] = logEntries[logCount - i];
        }
    }

    /**
     * @notice Transfer ownership to a new admin.
     * @param newOwner  Non-zero address of the new owner.
     */
    function transferOwnership(address newOwner) external onlyOwner {
        require(newOwner != address(0), "EventLogger: zero address");
        owner = newOwner;
    }
}

contracts/PipelineRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

/**
 * @title  PipelineRegistry
 * @notice Stores and manages approved pipeline configuration hashes.
 *         Only the contract owner (the project admin) can register or
 *         revoke approved hashes. The GitHub Actions logger queries
 *         this contract to confirm a pipeline config is legitimate
 *         before allowing a deployment to proceed.
 *
 * @dev    Deployed once to Sepolia testnet. Address stored in .env
 *         and loaded by logger/config.js.
 */
contract PipelineRegistry {

    // ─────────────────────────────────────────────
    //  State variables
    // ─────────────────────────────────────────────

    /// @notice Address that deployed this contract — the only account
    ///         allowed to register or revoke pipeline configs.
    address public owner;

    /// @notice Human-readable name for this registry entry, e.g. "main-pipeline"
    ///         keyed by pipeline ID.
    mapping(uint256 => string) public pipelineNames;

    /// @notice The SHA-256 hash of the approved .github/workflows/pipeline.yml
    ///         for each registered pipeline ID.
    ///         Stored as bytes32 for gas efficiency.
    mapping(uint256 => bytes32) public approvedHashes;

    /// @notice Tracks whether a pipeline ID has been registered.
    mapping(uint256 => bool) public isRegistered;

    /// @notice Tracks whether a pipeline ID has been revoked (soft-delete).
    mapping(uint256 => bool) public isRevoked;

    /// @notice Auto-incrementing ID counter for pipelines.
    uint256 public pipelineCount;

    // ─────────────────────────────────────────────
    //  Events
    // ─────────────────────────────────────────────

    /**
     * @notice Emitted when a new pipeline config is registered.
     * @param pipelineId  The unique ID assigned to this pipeline.
     * @param name        Human-readable label for the pipeline.
     * @param configHash  SHA-256 hash of the approved workflow YAML file.
     * @param registeredBy  The address that performed the registration.
     * @param timestamp   Block timestamp of registration.
     */
    event PipelineRegistered(
        uint256 indexed pipelineId,
        string  name,
        bytes32 configHash,
        address indexed registeredBy,
        uint256 timestamp
    );

    /**
     * @notice Emitted when an existing pipeline's approved hash is updated.
     * @param pipelineId  The pipeline being updated.
     * @param oldHash     The previous approved hash (for audit trail).
     * @param newHash     The new approved hash.
     * @param updatedBy   Address that performed the update.
     * @param timestamp   Block timestamp of update.
     */
    event PipelineHashUpdated(
        uint256 indexed pipelineId,
        bytes32 oldHash,
        bytes32 newHash,
        address indexed updatedBy,
        uint256 timestamp
    );

    /**
     * @notice Emitted when a pipeline is revoked (deactivated).
     * @param pipelineId  The pipeline being revoked.
     * @param revokedBy   Address that performed the revocation.
     * @param timestamp   Block timestamp of revocation.
     */
    event PipelineRevoked(
        uint256 indexed pipelineId,
        address indexed revokedBy,
        uint256 timestamp
    );

    // ─────────────────────────────────────────────
    //  Modifiers
    // ─────────────────────────────────────────────

    /// @dev Restricts a function to the contract owner only.
    modifier onlyOwner() {
        require(msg.sender == owner, "PipelineRegistry: caller is not the owner");
        _;
    }

    /// @dev Ensures the given pipeline ID has been registered.
    modifier pipelineExists(uint256 pipelineId) {
        require(isRegistered[pipelineId], "PipelineRegistry: pipeline not found");
        _;
    }

    /// @dev Ensures the given pipeline ID has NOT been revoked.
    modifier notRevoked(uint256 pipelineId) {
        require(!isRevoked[pipelineId], "PipelineRegistry: pipeline is revoked");
        _;
    }

    // ─────────────────────────────────────────────
    //  Constructor
    // ─────────────────────────────────────────────

    /**
     * @notice Sets the deploying address as the contract owner.
     */
    constructor() {
        owner = msg.sender;
    }

    // ─────────────────────────────────────────────
    //  Write functions (owner only)
    // ─────────────────────────────────────────────

    /**
     * @notice Register a new pipeline with its approved config hash.
     * @param name        A short label, e.g. "main-branch-pipeline".
     * @param configHash  SHA-256 hash of the workflow YAML, as bytes32.
     * @return pipelineId The unique ID assigned to the new pipeline.
     *
     * @dev   The caller should compute the SHA-256 hash off-chain
     *        (in hash-generator.js) and pass it as a bytes32 value.
     *        Example from JS:
     *          const hash = ethers.utils.sha256(fileBuffer);  // "0x..."
     */
    function registerPipeline(
        string calldata name,
        bytes32 configHash
    ) external onlyOwner returns (uint256 pipelineId) {
        require(bytes(name).length > 0,       "PipelineRegistry: name cannot be empty");
        require(configHash != bytes32(0),     "PipelineRegistry: hash cannot be zero");

        pipelineId = ++pipelineCount;

        pipelineNames[pipelineId]  = name;
        approvedHashes[pipelineId] = configHash;
        isRegistered[pipelineId]   = true;
        isRevoked[pipelineId]      = false;

        emit PipelineRegistered(
            pipelineId,
            name,
            configHash,
            msg.sender,
            block.timestamp
        );
    }

    /**
     * @notice Update the approved hash for an existing pipeline.
     *         Use this when you intentionally change your workflow YAML
     *         and want to re-approve the new version.
     * @param pipelineId  The pipeline to update.
     * @param newHash     The SHA-256 hash of the newly approved YAML.
     */
    function updateApprovedHash(
        uint256 pipelineId,
        bytes32 newHash
    )
        external
        onlyOwner
        pipelineExists(pipelineId)
        notRevoked(pipelineId)
    {
        require(newHash != bytes32(0), "PipelineRegistry: hash cannot be zero");

        bytes32 oldHash = approvedHashes[pipelineId];
        approvedHashes[pipelineId] = newHash;

        emit PipelineHashUpdated(
            pipelineId,
            oldHash,
            newHash,
            msg.sender,
            block.timestamp
        );
    }

    /**
     * @notice Revoke a pipeline, preventing it from passing verification.
     *         This is a soft-delete — the pipeline history is preserved
     *         on-chain for audit purposes.
     * @param pipelineId  The pipeline to revoke.
     */
    function revokePipeline(
        uint256 pipelineId
    )
        external
        onlyOwner
        pipelineExists(pipelineId)
        notRevoked(pipelineId)
    {
        isRevoked[pipelineId] = true;

        emit PipelineRevoked(
            pipelineId,
            msg.sender,
            block.timestamp
        );
    }

    // ─────────────────────────────────────────────
    //  Read functions (public — anyone can verify)
    // ─────────────────────────────────────────────

    /**
     * @notice Check whether a given hash matches the approved hash
     *         for a pipeline. This is the core integrity check called
     *         by Verifier.sol and blockchain-logger.js.
     *
     * @param pipelineId    The pipeline to check against.
     * @param candidateHash The SHA-256 hash of the currently running
     *                      workflow YAML, computed at runtime by the CI job.
     * @return isValid      True only if the pipeline is registered, not
     *                      revoked, and the hash matches exactly.
     */
    function verifyHash(
        uint256 pipelineId,
        bytes32 candidateHash
    ) external view returns (bool isValid) {
        if (!isRegistered[pipelineId]) return false;
        if ( isRevoked[pipelineId])   return false;

        return approvedHashes[pipelineId] == candidateHash;
    }

    /**
     * @notice Fetch all stored details for a pipeline in one call.
     * @param pipelineId  The pipeline to query.
     * @return name         Human-readable label.
     * @return configHash   The currently approved hash.
     * @return registered   Whether it has been registered.
     * @return revoked      Whether it has been revoked.
     */
    function getPipeline(uint256 pipelineId)
        external
        view
        returns (
            string  memory name,
            bytes32        configHash,
            bool           registered,
            bool           revoked
        )
    {
        return (
            pipelineNames[pipelineId],
            approvedHashes[pipelineId],
            isRegistered[pipelineId],
            isRevoked[pipelineId]
        );
    }

    /**
     * @notice Transfer ownership of the registry to a new admin address.
     * @param newOwner  Must be a non-zero address.
     */
    function transferOwnership(address newOwner) external onlyOwner {
        require(newOwner != address(0), "PipelineRegistry: new owner is zero address");
        owner = newOwner;
    }
}

contracts/Verifier.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

/**
 * @notice Minimal interface for PipelineRegistry — only the
 *         functions Verifier needs to call.
 */
interface IPipelineRegistry {
    function verifyHash(
        uint256 pipelineId,
        bytes32 candidateHash
    ) external view returns (bool isValid);

    function getPipeline(uint256 pipelineId)
        external
        view
        returns (
            string  memory name,
            bytes32        configHash,
            bool           registered,
            bool           revoked
        );
}

/**
 * @notice Minimal interface for EventLogger — only logEvent.
 */
interface IEventLogger {
    enum Stage {
        PIPELINE_TRIGGERED,
        BUILD_STARTED,
        BUILD_SUCCESS,
        BUILD_FAILED,
        TESTS_STARTED,
        TESTS_PASSED,
        TESTS_FAILED,
        INTEGRITY_VERIFIED,  // index 7
        INTEGRITY_FAILED,    // index 8
        DEPLOY_STARTED,
        DEPLOY_SUCCESS,
        DEPLOY_FAILED
    }

    function logEvent(
        uint256 pipelineId,
        uint256 runId,
        Stage   stage,
        bytes32 configHash,
        string  calldata commitHash,
        string  calldata actor,
        string  calldata notes
    ) external returns (uint256 logId);
}

// ─────────────────────────────────────────────────────────────────────────────

/**
 * @title  Verifier
 * @notice The integrity gate of the system.
 *
 *         GitHub Actions calls this contract (via blockchain-logger.js)
 *         just before the deploy step. Verifier:
 *
 *           1. Asks PipelineRegistry whether the live workflow hash
 *              matches the stored approved hash.
 *           2. Emits a VerificationResult event with the outcome.
 *           3. Tells EventLogger to record INTEGRITY_VERIFIED or
 *              INTEGRITY_FAILED so the audit trail is complete.
 *           4. Returns the boolean result to the caller — the GitHub
 *              Actions job aborts the deploy if false.
 *
 * @dev    Deployed after PipelineRegistry and EventLogger.
 *         Their addresses are passed to the constructor and stored
 *         immutably, preventing post-deployment tampering.
 */
contract Verifier {

    // ─────────────────────────────────────────────
    //  Immutable contract references
    // ─────────────────────────────────────────────

    /// @notice Address of the deployed PipelineRegistry contract.
    ///         Immutable — cannot be changed after deployment.
    IPipelineRegistry public immutable registry;

    /// @notice Address of the deployed EventLogger contract.
    ///         Immutable — cannot be changed after deployment.
    IEventLogger public immutable logger;

    // ─────────────────────────────────────────────
    //  State variables
    // ─────────────────────────────────────────────

    /// @notice Contract owner — the only address that can authorise callers.
    address public owner;

    /// @notice Addresses permitted to trigger verifications.
    ///         Must include the GitHub Actions bot wallet.
    mapping(address => bool) public authorisedCallers;

    /// @notice Total number of verifications performed (pass + fail).
    uint256 public verificationCount;

    /// @notice Total number of failed verifications — useful for the dashboard.
    uint256 public failureCount;

    // ─────────────────────────────────────────────
    //  Structs
    // ─────────────────────────────────────────────

    /**
     * @notice Full record of one verification attempt, stored on-chain.
     * @param verificationId  Auto-incremented unique ID.
     * @param pipelineId      The pipeline checked.
     * @param runId           GitHub Actions run ID.
     * @param candidateHash   Hash of the live workflow YAML at check time.
     * @param approvedHash    Hash stored in PipelineRegistry at check time.
     * @param passed          True if the hashes matched.
     * @param commitHash      Git commit SHA of the triggering push.
     * @param actor           GitHub username that triggered the run.
     * @param checkedBy       Bot wallet address that called this function.
     * @param timestamp       Block timestamp of the verification.
     */
    struct VerificationRecord {
        uint256 verificationId;
        uint256 pipelineId;
        uint256 runId;
        bytes32 candidateHash;
        bytes32 approvedHash;
        bool    passed;
        string  commitHash;
        string  actor;
        address checkedBy;
        uint256 timestamp;
    }

    /// @notice All verification records, indexed by verificationId (1-based).
    mapping(uint256 => VerificationRecord) public verifications;

    /// @notice All verificationIds for a given pipelineId.
    mapping(uint256 => uint256[]) public verificationsByPipeline;

    // ─────────────────────────────────────────────
    //  Events
    // ─────────────────────────────────────────────

    /**
     * @notice Emitted on every verification attempt, pass or fail.
     *         The dashboard listens for this to show integrity status.
     *
     * @param verificationId  Unique ID of this check.
     * @param pipelineId      The pipeline that was checked.
     * @param runId           GitHub Actions run ID.
     * @param candidateHash   Hash presented by the running pipeline.
     * @param approvedHash    Hash on record in PipelineRegistry.
     * @param passed          Whether they matched.
     * @param actor           Who triggered the run.
     * @param timestamp       When the check happened.
     */
    event VerificationResult(
        uint256 indexed verificationId,
        uint256 indexed pipelineId,
        uint256 indexed runId,
        bytes32         candidateHash,
        bytes32         approvedHash,
        bool            passed,
        string          actor,
        uint256         timestamp
    );

    /**
     * @notice Emitted specifically on a tamper detection (hash mismatch).
     *         Useful for dashboards or alerting systems that filter
     *         only on failure events.
     *
     * @param pipelineId     The affected pipeline.
     * @param runId          The run where tampering was detected.
     * @param candidateHash  The unexpected hash found in the live workflow.
     * @param approvedHash   The hash that was expected.
     * @param actor          Who triggered the run.
     * @param timestamp      When it was detected.
     */
    event TamperDetected(
        uint256 indexed pipelineId,
        uint256 indexed runId,
        bytes32         candidateHash,
        bytes32         approvedHash,
        string          actor,
        uint256         timestamp
    );

    /// @notice Emitted when a caller is authorised.
    event CallerAuthorised(address indexed caller, uint256 timestamp);

    /// @notice Emitted when a caller is revoked.
    event CallerRevoked(address indexed caller, uint256 timestamp);

    // ─────────────────────────────────────────────
    //  Modifiers
    // ─────────────────────────────────────────────

    modifier onlyOwner() {
        require(msg.sender == owner, "Verifier: caller is not the owner");
        _;
    }

    modifier onlyAuthorised() {
        require(
            authorisedCallers[msg.sender] || msg.sender == owner,
            "Verifier: caller is not authorised"
        );
        _;
    }

    // ─────────────────────────────────────────────
    //  Constructor
    // ─────────────────────────────────────────────

    /**
     * @notice Wires Verifier to the already-deployed PipelineRegistry
     *         and EventLogger contracts.
     *
     * @param registryAddress  Address of the deployed PipelineRegistry.
     * @param loggerAddress    Address of the deployed EventLogger.
     *
     * @dev    Run deploy.js which deploys all three contracts in order
     *         and passes these addresses automatically.
     */
    constructor(address registryAddress, address loggerAddress) {
        require(registryAddress != address(0), "Verifier: invalid registry address");
        require(loggerAddress   != address(0), "Verifier: invalid logger address");

        registry = IPipelineRegistry(registryAddress);
        logger   = IEventLogger(loggerAddress);
        owner    = msg.sender;

        authorisedCallers[msg.sender] = true;
        emit CallerAuthorised(msg.sender, block.timestamp);
    }

    // ─────────────────────────────────────────────
    //  Access control
    // ─────────────────────────────────────────────

    /**
     * @notice Authorise a wallet to call verify().
     *         Add your GitHub Actions bot wallet here after deployment.
     */
    function authoriseCaller(address caller) external onlyOwner {
        require(caller != address(0), "Verifier: zero address");
        authorisedCallers[caller] = true;
        emit CallerAuthorised(caller, block.timestamp);
    }

    /**
     * @notice Revoke a wallet's permission to call verify().
     */
    function revokeCaller(address caller) external onlyOwner {
        authorisedCallers[caller] = false;
        emit CallerRevoked(caller, block.timestamp);
    }

    // ─────────────────────────────────────────────
    //  Core verification function
    // ─────────────────────────────────────────────

    /**
     * @notice Perform an integrity check on a pipeline run.
     *
     *         This is the single most important function in the system.
     *         It is called by blockchain-logger.js at the "verify" step
     *         of the GitHub Actions workflow, before deployment begins.
     *
     *         Flow:
     *           1. Fetches the approved hash from PipelineRegistry.
     *           2. Compares it to the candidateHash computed at runtime.
     *           3. Stores a VerificationRecord on-chain.
     *           4. Emits VerificationResult (always) and TamperDetected
     *              (only on failure).
     *           5. Calls EventLogger to append INTEGRITY_VERIFIED or
     *              INTEGRITY_FAILED to the audit trail.
     *           6. Returns the boolean result — the GitHub Actions step
     *              checks this and aborts the deploy if false.
     *
     * @param pipelineId     ID from PipelineRegistry for this pipeline.
     * @param runId          GitHub Actions ${{ github.run_id }}.
     * @param candidateHash  SHA-256 of the live .github/workflows/pipeline.yml,
     *                       computed by hash-generator.js at runtime.
     * @param commitHash     Git commit SHA that triggered this run.
     * @param actor          GitHub username that triggered the run.
     *
     * @return passed        True if hashes match and pipeline is not revoked.
     * @return verificationId  The ID of the stored VerificationRecord.
     */
    function verify(
        uint256 pipelineId,
        uint256 runId,
        bytes32 candidateHash,
        string  calldata commitHash,
        string  calldata actor
    )
        external
        onlyAuthorised
        returns (bool passed, uint256 verificationId)
    {
        require(pipelineId > 0,               "Verifier: invalid pipelineId");
        require(runId > 0,                    "Verifier: invalid runId");
        require(candidateHash != bytes32(0),  "Verifier: candidateHash required");
        require(bytes(commitHash).length > 0, "Verifier: commitHash required");
        require(bytes(actor).length > 0,      "Verifier: actor required");

        // ── 1. Fetch the approved hash from PipelineRegistry ──
        (
            ,                    // name (unused here)
            bytes32 approvedHash,
            bool    registered,
            bool    revoked
        ) = registry.getPipeline(pipelineId);

        // ── 2. Determine pass/fail ──
        //    Fails if: pipeline not registered, pipeline revoked,
        //    or hash does not match exactly.
        if (!registered || revoked) {
            passed = false;
        } else {
            passed = (approvedHash == candidateHash);
        }

        // ── 3. Store the VerificationRecord on-chain ──
        verificationId = ++verificationCount;

        verifications[verificationId] = VerificationRecord({
            verificationId: verificationId,
            pipelineId:     pipelineId,
            runId:          runId,
            candidateHash:  candidateHash,
            approvedHash:   approvedHash,
            passed:         passed,
            commitHash:     commitHash,
            actor:          actor,
            checkedBy:      msg.sender,
            timestamp:      block.timestamp
        });

        verificationsByPipeline[pipelineId].push(verificationId);

        if (!passed) {
            unchecked { failureCount++; }
        }

        // ── 4. Emit events ──
        emit VerificationResult(
            verificationId,
            pipelineId,
            runId,
            candidateHash,
            approvedHash,
            passed,
            actor,
            block.timestamp
        );

        if (!passed) {
            emit TamperDetected(
                pipelineId,
                runId,
                candidateHash,
                approvedHash,
                actor,
                block.timestamp
            );
        }

        // ── 5. Append to EventLogger audit trail ──
        //    Use a try/catch so a logger failure never blocks verification.
        IEventLogger.Stage logStage = passed
            ? IEventLogger.Stage.INTEGRITY_VERIFIED
            : IEventLogger.Stage.INTEGRITY_FAILED;

        string memory notes = passed
            ? "Hash matched approved config"
            : "TAMPER DETECTED: hash mismatch";

        try logger.logEvent(
            pipelineId,
            runId,
            logStage,
            candidateHash,
            commitHash,
            actor,
            notes
        ) {} catch {}
        // ↑ Silent catch: the verification result is already stored
        //   on-chain and emitted as an event. A logger hiccup must
        //   never block or revert the verification itself.

        // ── 6. Return result to blockchain-logger.js ──
        return (passed, verificationId);
    }

    // ─────────────────────────────────────────────
    //  Read functions
    // ─────────────────────────────────────────────

    /**
     * @notice Read-only integrity check — does NOT store a record or
     *         emit events. Use for off-chain checks or dashboard previews.
     *
     * @param pipelineId     The pipeline to check.
     * @param candidateHash  The hash to test.
     * @return               True if the hash matches the approved hash.
     */
    function checkOnly(
        uint256 pipelineId,
        bytes32 candidateHash
    ) external view returns (bool) {
        return registry.verifyHash(pipelineId, candidateHash);
    }

    /**
     * @notice Fetch a stored VerificationRecord by its ID.
     */
    function getVerification(uint256 verificationId)
        external
        view
        returns (VerificationRecord memory)
    {
        require(
            verificationId > 0 && verificationId <= verificationCount,
            "Verifier: record not found"
        );
        return verifications[verificationId];
    }

    /**
     * @notice Get all verificationIds for a given pipeline.
     */
    function getVerificationsByPipeline(uint256 pipelineId)
        external
        view
        returns (uint256[] memory)
    {
        return verificationsByPipeline[pipelineId];
    }

    /**
     * @notice Quick summary stats for the dashboard header.
     * @return total    Total verifications performed.
     * @return failures Total failed verifications (tamper detections).
     * @return passes   Total passed verifications.
     */
    function getStats()
        external
        view
        returns (uint256 total, uint256 failures, uint256 passes)
    {
        total    = verificationCount;
        failures = failureCount;
        passes   = verificationCount - failureCount;
    }

    /**
     * @notice Transfer ownership to a new admin.
     */
    function transferOwnership(address newOwner) external onlyOwner {
        require(newOwner != address(0), "Verifier: zero address");
        owner = newOwner;
    }
}

